import React from 'react';
import { Link, Navigate } from 'react-router-dom'

const Home = () => {
    return (
        <>
            <div className='container'>
                <div className='main-heading'>
                    <div>Welcome to your world—where</div>
                    <div>it gets the attention it quietly deserves.</div>
                </div>

                <div className='main-menu'>
                    <Link to="/journal"><div className='menu-box'>Journal</div>
                    </Link>
                    <Link className='menu-box' to="/mood"><div className='menu-box'>Mood</div>
                    </Link>
                    <Link className='menu-box' to="/tasks"><div className='menu-box'>Tasks</div>
                    </Link>
                    <Link className='menu-box' to="/dashboard"><div className='menu-box'>DashBoard</div>
                    </Link>

                </div>

                <div className='design-layout'>
                    <img className='design' src='/assets/background1.png' alt="Design" />
                </div>

                <div className='footer-heading'>
                    DearDiary - Divya
                </div>
            </div>
            <Stylesheet />
        </>
    );
};

const Stylesheet = () => {
    return <style>{`
        .container {
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: space-between;
            min-height: 100vh;
            padding: 2rem;
            box-sizing: border-box;
        }

        .main-heading {
            font-size: 3.5rem;
            text-align: center;
            margin-top: 2rem;
        }
        .main-menu {
            display: flex;
            flex-wrap: wrap;
            justify-content: center;
            gap: 1.5rem;
            margin: 3rem 0;
        }

        .menu-box {
            background-color: var(--secondary-color);
            width: 150px;
            height: 150px;
            display: flex;
            align-items: center;
            justify-content: center;
            border-radius: 10px;
            font-size: 2rem;
            transition: all 0.3s ease-in-out;
        }

        .menu-box:hover {
            transform: scale(1.05);
            box-shadow: 0 4px 20px rgba(0, 0, 0, 0.15);
        }

        .design-layout {
            display: flex;
            justify-content: center;
            margin: 2rem 0;
            width: 100%;
        }

        .design {
            width: 80%;
            max-width: 700px;
            height: auto;
            opacity: 0.8;
        }

        .footer-heading {
            text-align: center;
            font-size: 2rem;
            margin-bottom: 1rem;
        }

        @media (max-width: 768px) {
            .main-heading {
                font-size: 1.7rem;
            }

            .menu-box {
                width: 120px;
                height: 120px;
                font-size: 1.8rem;
            }

            .footer-heading {
                font-size: 1.8rem;
            }
        }

        @media (max-width: 480px) {
            .main-heading {
                font-size: 1.6rem;
            }

            .menu-box {
                width: 100px;
                height: 100px;
                font-size: 1.4rem;
            }

            .footer-heading {
                font-size: 1.4rem;
            }
        }
    `}</style>;
};

export default Home;
